import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface NcmTax {
  name: string;
  rate: string;
  description?: string;
}

export interface NcmData {
  code: string;
  description: string;
  sector?: string;
  taxes: {
    ii: string;
    ipi: string;
    pis: string;
    cofins: string;
    icms_avg: string;
  };
  restrictions?: string[];
  relevance?: number;
}

export interface SearchHistory {
  query: string;
  timestamp: number;
}

export enum ViewMode {
  SEARCH = 'search',
  FAVORITES = 'favorites',
  HISTORY = 'history',
  DETAILS = 'details'
}

import { GoogleGenAI, Type } from "@google/genai";
import { NcmData } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });

const NCM_SCHEMA = {
  type: Type.ARRAY,
  items: {
    type: Type.OBJECT,
    properties: {
      code: { type: Type.STRING, description: "Código NCM formatado (ex: 8517.12.00)" },
      description: { type: Type.STRING, description: "Descrição oficial da Nomenclatura" },
      sector: { type: Type.STRING, description: "Setor comercial/industrial geral" },
      taxes: {
        type: Type.OBJECT,
        properties: {
          ii: { type: Type.STRING, description: "Alíquota Imposto de Importação (%)" },
          ipi: { type: Type.STRING, description: "Alíquota IPI (%)" },
          pis: { type: Type.STRING, description: "Alíquota PIS (%)" },
          cofins: { type: Type.STRING, description: "Alíquota COFINS (%)" },
          icms_avg: { type: Type.STRING, description: "Média estimada ICMS (%)" }
        },
        required: ["ii", "ipi", "pis", "cofins", "icms_avg"]
      },
      restrictions: {
        type: Type.ARRAY,
        items: { type: Type.STRING },
        description: "Eventuais restrições ou licenças de importação"
      },
      relevance: { type: Type.NUMBER, description: "Score de relevância de 0 a 1" }
    },
    required: ["code", "description", "taxes"]
  }
};

export const searchNcm = async (query: string): Promise<NcmData[]> => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Atue como um especialista fiscal brasileiro. Busque o código NCM (ou uma lista de códigos relevantes) para a consulta: "${query}". 
      Considere sinônimos, termos coloquiais e possíveis erros de digitação. 
      Retorne os dados formatados exatamente de acordo com a tabela oficial da Receita Federal e TEC (Tarifa Externa Comum).`,
      config: {
        responseMimeType: "application/json",
        responseSchema: NCM_SCHEMA as any,
      },
    });

    const results = JSON.parse(response.text || "[]");
    return results;
  } catch (error) {
    console.error("Erro ao buscar NCM:", error);
    return [];
  }
};

export const getNcmByCode = async (code: string): Promise<NcmData | null> => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Forneça os detalhes completos do NCM "${code}". Inclua alíquotas de II, IPI, PIS, COFINS e a descrição oficial completa.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY, // We use array but expect 1 item
          items: (NCM_SCHEMA as any).items
        } as any,
      },
    });

    const results = JSON.parse(response.text || "[]");
    return results.length > 0 ? results[0] : null;
  } catch (error) {
    console.error("Erro ao obter detalhes do NCM:", error);
    return null;
  }
};

import React from 'react';
import { NcmData } from '../types';

interface NcmCardProps {
  ncm: NcmData;
  onSelect: (ncm: NcmData) => void;
  isFavorite: boolean;
  onToggleFavorite: (e: React.MouseEvent, ncm: NcmData) => void;
}

const NcmCard: React.FC<NcmCardProps> = ({ ncm, onSelect, isFavorite, onToggleFavorite }) => {
  return (
    <div 
      onClick={() => onSelect(ncm)}
      className="bg-white p-4 rounded-xl border border-slate-200 shadow-sm hover:shadow-md transition-all cursor-pointer group"
    >
      <div className="flex justify-between items-start mb-2">
        <span className="text-blue-600 font-mono font-bold text-lg">{ncm.code}</span>
        <button 
          onClick={(e) => onToggleFavorite(e, ncm)}
          className={`text-xl transition-colors ${isFavorite ? 'text-amber-400' : 'text-slate-300 hover:text-amber-300'}`}
        >
          <i className={isFavorite ? "fas fa-star" : "far fa-star"}></i>
        </button>
      </div>

      <p className="text-slate-700 text-sm line-clamp-2 mb-3 leading-relaxed">
        {ncm.description}
      </p>

      <div className="flex flex-wrap gap-2 mt-auto">
        {ncm.sector && (
          <span className="text-[10px] uppercase tracking-wider font-semibold px-2 py-1 bg-slate-100 text-slate-500 rounded">
            {ncm.sector}
          </span>
        )}
        <div className="flex gap-2 ml-auto">
          <div className="text-[10px] text-slate-400">
            IPI: <span className="font-semibold text-slate-600">{ncm.taxes.ipi}</span>
          </div>
          <div className="text-[10px] text-slate-400">
            II: <span className="font-semibold text-slate-600">{ncm.taxes.ii}</span>
          </div>
        </div>
      </div>
    </div>
  );
};

export default NcmCard;

import React, { useState, useEffect, useCallback } from 'react';
import { NcmData, SearchHistory, ViewMode } from './types';
import { searchNcm } from './services/geminiService';
import NcmCard from './components/NcmCard';

const App: React.FC = () => {
  const [query, setQuery] = useState('');
  const [results, setResults] = useState<NcmData[]>([]);
  const [loading, setLoading] = useState(false);
  const [view, setView] = useState<ViewMode>(ViewMode.SEARCH);
  const [selectedNcm, setSelectedNcm] = useState<NcmData | null>(null);
  const [favorites, setFavorites] = useState<NcmData[]>([]);
  const [history, setHistory] = useState<SearchHistory[]>([]);
  const [activeFilter, setActiveFilter] = useState<string | null>(null);

  // Persistence
  useEffect(() => {
    const savedFavorites = localStorage.getItem('ncm_favorites');
    const savedHistory = localStorage.getItem('ncm_history');
    if (savedFavorites) setFavorites(JSON.parse(savedFavorites));
    if (savedHistory) setHistory(JSON.parse(savedHistory));
  }, []);

  useEffect(() => {
    localStorage.setItem('ncm_favorites', JSON.stringify(favorites));
  }, [favorites]);

  useEffect(() => {
    localStorage.setItem('ncm_history', JSON.stringify(history));
  }, [history]);

  const handleSearch = async (e?: React.FormEvent) => {
    if (e) e.preventDefault();
    if (!query.trim()) return;

    setLoading(true);
    setView(ViewMode.SEARCH);

    // Add to history
    const newHistory = [
      { query, timestamp: Date.now() },
      ...history.filter(h => h.query !== query)
    ].slice(0, 10);
    setHistory(newHistory);

    const data = await searchNcm(query);
    setResults(data);
    setLoading(false);
  };

  const toggleFavorite = (e: React.MouseEvent, ncm: NcmData) => {
    e.stopPropagation();
    const isFav = favorites.some(f => f.code === ncm.code);
    if (isFav) {
      setFavorites(favorites.filter(f => f.code !== ncm.code));
    } else {
      setFavorites([...favorites, ncm]);
    }
  };

  const handleSelectNcm = (ncm: NcmData) => {
    setSelectedNcm(ncm);
    setView(ViewMode.DETAILS);
  };

  const clearHistory = () => {
    setHistory([]);
    localStorage.removeItem('ncm_history');
  };

  const filteredResults = activeFilter 
    ? results.filter(r => r.sector?.toLowerCase().includes(activeFilter.toLowerCase()))
    : results;

  const sectors = Array.from(new Set(results.map(r => r.sector).filter(Boolean))) as string[];

  return (
    <div className="min-h-screen flex flex-col md:flex-row">
      {/* Sidebar Navigation */}
      <nav className="w-full md:w-64 bg-slate-900 text-slate-300 p-6 flex flex-col shrink-0">
        <div className="flex items-center gap-3 mb-10">
          <div className="bg-blue-600 p-2 rounded-lg text-white">
            <i className="fas fa-file-invoice-dollar text-xl"></i>
          </div>
          <h1 className="text-xl font-bold text-white tracking-tight">NCM Inteligente</h1>
        </div>

        <ul className="space-y-2 flex-grow">
          <li>
            <button 
              onClick={() => setView(ViewMode.SEARCH)}
              className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition-colors ${view === ViewMode.SEARCH ? 'bg-slate-800 text-white shadow-sm' : 'hover:bg-slate-800'}`}
            >
              <i className="fas fa-search"></i> Buscar
            </button>
          </li>
          <li>
            <button 
              onClick={() => setView(ViewMode.FAVORITES)}
              className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition-colors ${view === ViewMode.FAVORITES ? 'bg-slate-800 text-white shadow-sm' : 'hover:bg-slate-800'}`}
            >
              <i className="fas fa-star"></i> Favoritos
            </button>
          </li>
          <li>
            <button 
              onClick={() => setView(ViewMode.HISTORY)}
              className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition-colors ${view === ViewMode.HISTORY ? 'bg-slate-800 text-white shadow-sm' : 'hover:bg-slate-800'}`}
            >
              <i className="fas fa-clock-rotate-left"></i> Histórico
            </button>
          </li>
        </ul>

        <div className="mt-auto pt-6 border-t border-slate-800 text-xs text-slate-500">
          <p>Fonte: Receita Federal & TEC</p>
          <p>© 2024 NCM Inteligente</p>
        </div>
      </nav>

      {/* Main Content Area */}
      <main className="flex-grow p-4 md:p-10 overflow-y-auto max-h-screen">
        {/* Header/Search Bar */}
        <header className="mb-8 max-w-4xl mx-auto">
          <form onSubmit={handleSearch} className="relative group">
            <input 
              type="text" 
              value={query}
              onChange={(e) => setQuery(e.target.value)}
              placeholder="Digite o código (ex: 8517.12) ou nome do produto..."
              className="w-full pl-12 pr-4 py-4 bg-white border border-slate-200 rounded-2xl shadow-sm focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all group-hover:shadow-md text-lg"
            />
            <i className="fas fa-search absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 text-xl"></i>
            <button 
              type="submit"
              disabled={loading}
              className="absolute right-3 top-1/2 -translate-y-1/2 bg-blue-600 hover:bg-blue-700 text-white px-6 py-2 rounded-xl transition-colors font-semibold disabled:opacity-50"
            >
              {loading ? <i className="fas fa-circle-notch fa-spin"></i> : 'Consultar'}
            </button>
          </form>
          {view === ViewMode.SEARCH && results.length > 0 && (
            <div className="mt-4 flex flex-wrap gap-2">
               <button 
                onClick={() => setActiveFilter(null)}
                className={`px-3 py-1 rounded-full text-xs font-medium border transition-colors ${!activeFilter ? 'bg-blue-100 text-blue-700 border-blue-200' : 'bg-white text-slate-600 border-slate-200'}`}
              >
                Todos
              </button>
              {sectors.map(s => (
                <button 
                  key={s}
                  onClick={() => setActiveFilter(s === activeFilter ? null : s)}
                  className={`px-3 py-1 rounded-full text-xs font-medium border transition-colors ${activeFilter === s ? 'bg-blue-100 text-blue-700 border-blue-200' : 'bg-white text-slate-600 border-slate-200'}`}
                >
                  {s}
                </button>
              ))}
            </div>
          )}
        </header>

        {/* Dynamic Views */}
        <div className="max-w-6xl mx-auto">
          {view === ViewMode.SEARCH && (
            <>
              {loading ? (
                <div className="flex flex-col items-center justify-center py-20 text-slate-400">
                  <i className="fas fa-magnifying-glass fa-bounce text-5xl mb-4 text-blue-500"></i>
                  <p className="animate-pulse">Analisando nomenclatura e buscando impostos...</p>
                </div>
              ) : results.length > 0 ? (
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                  {filteredResults.map(ncm => (
                    <NcmCard 
                      key={ncm.code} 
                      ncm={ncm} 
                      onSelect={handleSelectNcm}
                      isFavorite={favorites.some(f => f.code === ncm.code)}
                      onToggleFavorite={toggleFavorite}
                    />
                  ))}
                </div>
              ) : query && !loading ? (
                <div className="text-center py-20 text-slate-400 bg-white rounded-3xl border border-dashed border-slate-300">
                  <i className="fas fa-box-open text-5xl mb-4 opacity-20"></i>
                  <p>Nenhum resultado encontrado para sua busca.</p>
                </div>
              ) : (
                <div className="flex flex-col items-center justify-center py-20 text-slate-400">
                   <img src="https://picsum.photos/seed/search/400/300" className="w-64 h-auto rounded-2xl opacity-50 grayscale mb-6" alt="Busca" />
                   <p className="text-lg max-w-sm text-center">Utilize inteligência artificial para encontrar o código fiscal correto em segundos.</p>
                </div>
              )}
            </>
          )}

          {view === ViewMode.FAVORITES && (
            <div>
              <div className="flex items-center justify-between mb-8">
                <h2 className="text-2xl font-bold text-slate-800">Meus Favoritos</h2>
                <span className="bg-slate-200 text-slate-600 px-3 py-1 rounded-full text-sm font-semibold">
                  {favorites.length} salvos
                </span>
              </div>
              {favorites.length > 0 ? (
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                  {favorites.map(ncm => (
                    <NcmCard 
                      key={ncm.code} 
                      ncm={ncm} 
                      onSelect={handleSelectNcm}
                      isFavorite={true}
                      onToggleFavorite={toggleFavorite}
                    />
                  ))}
                </div>
              ) : (
                <div className="text-center py-20 bg-white rounded-3xl border border-dashed border-slate-300">
                  <i className="fas fa-star text-slate-200 text-5xl mb-4"></i>
                  <p className="text-slate-500">Você ainda não salvou nenhum NCM como favorito.</p>
                </div>
              )}
            </div>
          )}

          {view === ViewMode.HISTORY && (
            <div className="max-w-2xl mx-auto">
              <div className="flex items-center justify-between mb-8">
                <h2 className="text-2xl font-bold text-slate-800">Buscas Recentes</h2>
                <button 
                  onClick={clearHistory}
                  className="text-red-500 hover:text-red-700 text-sm font-medium transition-colors"
                >
                  Limpar tudo
                </button>
              </div>
              {history.length > 0 ? (
                <div className="space-y-3">
                  {history.map((h, i) => (
                    <div 
                      key={i}
                      onClick={() => {
                        setQuery(h.query);
                        handleSearch();
                      }}
                      className="flex items-center justify-between p-4 bg-white border border-slate-200 rounded-xl hover:border-blue-300 cursor-pointer transition-all group shadow-sm"
                    >
                      <div className="flex items-center gap-4">
                        <i className="fas fa-clock-rotate-left text-slate-400 group-hover:text-blue-500"></i>
                        <span className="font-medium text-slate-700">{h.query}</span>
                      </div>
                      <span className="text-xs text-slate-400">
                        {new Date(h.timestamp).toLocaleDateString('pt-BR')}
                      </span>
                    </div>
                  ))}
                </div>
              ) : (
                <p className="text-center text-slate-500 py-20">Seu histórico de buscas está vazio.</p>
              )}
            </div>
          )}

          {view === ViewMode.DETAILS && selectedNcm && (
            <div className="bg-white rounded-3xl shadow-xl border border-slate-100 overflow-hidden max-w-4xl mx-auto animate-in fade-in zoom-in duration-300">
              <div className="bg-blue-600 p-8 text-white relative">
                <button 
                  onClick={() => setView(ViewMode.SEARCH)}
                  className="absolute left-6 top-6 text-white/80 hover:text-white transition-colors"
                >
                  <i className="fas fa-arrow-left text-xl"></i>
                </button>
                <div className="text-center">
                  <span className="inline-block px-4 py-1 bg-white/20 backdrop-blur rounded-full text-xs font-bold uppercase tracking-widest mb-4">Ficha Técnica Fiscal</span>
                  <h2 className="text-4xl font-mono font-black mb-2">{selectedNcm.code}</h2>
                  <p className="text-blue-100 text-lg leading-relaxed max-w-2xl mx-auto">
                    {selectedNcm.description}
                  </p>
                </div>
              </div>

              <div className="p-8">
                <div className="grid grid-cols-2 md:grid-cols-5 gap-4 mb-10">
                  <div className="p-4 bg-slate-50 rounded-2xl text-center border border-slate-100">
                    <p className="text-xs text-slate-400 font-bold uppercase mb-1">II</p>
                    <p className="text-2xl font-black text-slate-800">{selectedNcm.taxes.ii}</p>
                  </div>
                  <div className="p-4 bg-slate-50 rounded-2xl text-center border border-slate-100">
                    <p className="text-xs text-slate-400 font-bold uppercase mb-1">IPI</p>
                    <p className="text-2xl font-black text-slate-800">{selectedNcm.taxes.ipi}</p>
