                      Restrições e Alertas
                    </h3>
                    <div className="bg-amber-50 border border-amber-100 rounded-2xl p-6">
                      {selectedNcm.restrictions && selectedNcm.restrictions.length > 0 ? (
                        <ul className="space-y-3">
                          {selectedNcm.restrictions.map((r, i) => (
                            <li key={i} className="flex gap-3 text-amber-800 text-sm">
                              <span className="text-amber-300">•</span>
                              {r}
                            </li>
                          ))}
                        </ul>
                      ) : (
                        <p className="text-amber-800 text-sm italic">Nenhuma restrição especial listada para este código no regime geral.</p>
                      )}
                    </div>
                  </div>

                  <div>
                    <h3 className="text-lg font-bold text-slate-800 mb-4 flex items-center gap-2">
                      <i className="fas fa-circle-info text-blue-500"></i>
                      Contexto Comercial
                    </h3>
                    <div className="bg-slate-50 rounded-2xl p-6 text-sm text-slate-600 leading-relaxed">
                      Este código NCM é comumente aplicado no setor de <span className="font-bold text-slate-800">{selectedNcm.sector || 'Geral'}</span>. 
                      Para emissão de Notas Fiscais, certifique-se de que a descrição do produto na nota está alinhada à Nomenclatura Comum do Mercosul para evitar multas por classificação incorreta (Art. 711 do Regulamento Aduaneiro).
                    </div>
                  </div>
                </div>

                <div className="mt-10 flex gap-4">
                  <button 
                    onClick={(e) => toggleFavorite(e, selectedNcm)}
                    className={`flex-grow py-4 rounded-2xl font-bold transition-all flex items-center justify-center gap-3 ${favorites.some(f => f.code === selectedNcm.code) ? 'bg-amber-100 text-amber-700' : 'bg-slate-100 text-slate-700 hover:bg-slate-200'}`}
                  >
                    <i className={favorites.some(f => f.code === selectedNcm.code) ? "fas fa-star" : "far fa-star"}></i>
                    {favorites.some(f => f.code === selectedNcm.code) ? 'Remover dos Favoritos' : 'Salvar nos Favoritos'}
                  </button>
                  <button 
                    onClick={() => window.print()}
                    className="bg-slate-900 text-white px-8 rounded-2xl font-bold hover:bg-slate-800 transition-all flex items-center gap-3"
                  >
                    <i className="fas fa-print"></i>
                    Exportar PDF
                  </button>
                </div>
              </div>
            </div>
          )}
        </div>
      </main>
    </div>
  );
};

