    const data = await searchNcm(query);
    setResults(data);
    setLoading(false);
  };

  const toggleFavorite = (e: React.MouseEvent, ncm: NcmData) => {
    e.stopPropagation();
    const isFav = favorites.some(f => f.code === ncm.code);
    if (isFav) {
      setFavorites(favorites.filter(f => f.code !== ncm.code));
    } else {
      setFavorites([...favorites, ncm]);
    }
  };

  const handleSelectNcm = (ncm: NcmData) => {
    setSelectedNcm(ncm);
    setView(ViewMode.DETAILS);
  };

  const clearHistory = () => {
    setHistory([]);
    localStorage.removeItem('ncm_history');
  };

  const filteredResults = activeFilter 
    ? results.filter(r => r.sector?.toLowerCase().includes(activeFilter.toLowerCase()))
    : results;

  const sectors = Array.from(new Set(results.map(r => r.sector).filter(Boolean))) as string[];

  const resetApp = () => {
    setQuery('');
    setResults([]);
    setView(ViewMode.SEARCH);
    setActiveFilter(null);
  };

  return (
    <div className="min-h-screen flex flex-col md:flex-row">
      {/* Sidebar Navigation */}
      <nav className="w-full md:w-64 bg-slate-900 text-slate-300 p-6 flex flex-col shrink-0 border-r border-slate-800">
        {/* Detecta Logo Section */}
        <div 
          onClick={resetApp}
          className="mb-10 group cursor-pointer"
        >
          <div className="flex items-end gap-1.5 mb-2 h-12">
            <div className="w-2.5 bg-blue-700 h-full rounded-sm shadow-[0_0_10px_rgba(29,78,216,0.3)]"></div>
            <div className="w-2.5 bg-blue-600 h-5/6 rounded-sm"></div>
            <div className="w-2.5 bg-blue-500 h-4/6 rounded-sm"></div>
            <div className="ml-2 flex flex-col justify-end">
               <span className="text-[10px] text-blue-400 font-black tracking-[0.2em] mb-[-4px]">DESDE 1991</span>
               <h1 className="text-3xl font-black text-white tracking-tighter italic">Detecta</h1>
            </div>
          </div>
          <div className="h-0.5 w-full bg-gradient-to-r from-blue-600 to-transparent opacity-50 mb-1"></div>
          <p className="text-[9px] uppercase tracking-[0.15em] font-bold text-slate-500 group-hover:text-blue-400 transition-colors">Manutenção Industrial</p>
        </div>

        <ul className="space-y-2 flex-grow">
          <li>
            <button 
              onClick={() => setView(ViewMode.SEARCH)}
              className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition-colors ${view === ViewMode.SEARCH ? 'bg-blue-600/10 text-blue-400 shadow-sm border border-blue-600/20' : 'hover:bg-slate-800'}`}
            >
              <i className="fas fa-search"></i> Consulta NCM
            </button>
          </li>
          <li>
            <button 
              onClick={() => setView(ViewMode.FAVORITES)}
              className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition-colors ${view === ViewMode.FAVORITES ? 'bg-slate-800 text-white' : 'hover:bg-slate-800'}`}
            >
              <i className="fas fa-star"></i> Meus Favoritos
            </button>
          </li>
          <li>
            <button 
              onClick={() => setView(ViewMode.HISTORY)}
              className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition-colors ${view === ViewMode.HISTORY ? 'bg-slate-800 text-white' : 'hover:bg-slate-800'}`}
            >
              <i className="fas fa-history"></i> Histórico
            </button>
          </li>
        </ul>

        <div className="mt-auto pt-6 border-t border-slate-800">
          <div className="flex items-center gap-3 text-[10px] text-slate-500 mb-4 bg-slate-800/50 p-3 rounded-xl">
             <i className="fas fa-shield-halved text-blue-600 text-lg"></i>
             <div>
                <p className="font-bold text-slate-400">NCM INTELIGENTE</p>
                <p>Módulo de Inteligência Fiscal</p>
             </div>
          </div>
          <p className="text-[10px] text-slate-600 text-center">© Detecta Manutenção Industrial</p>
        </div>
      </nav>

      {/* Main Content Area */}
      <main className="flex-grow p-4 md:p-10 overflow-y-auto max-h-screen">
        {/* Header/Search Bar */}
        <header className="mb-8 max-w-4xl mx-auto">
          <form onSubmit={handleSearch} className="relative group">
            <input 
              type="text" 
              value={query}
              onChange={(e) => setQuery(e.target.value)}
              placeholder="Ex: 'parafuso inox', 'válvula' ou código 7318.15..."
              className="w-full pl-12 pr-4 py-5 bg-white border border-slate-200 rounded-2xl shadow-sm focus:ring-2 focus:ring-blue-600 focus:border-blue-600 outline-none transition-all group-hover:shadow-md text-lg"
            />
            <i className="fas fa-search absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 text-xl"></i>
            <button 
              type="submit"
              disabled={loading}
              className="absolute right-3 top-1/2 -translate-y-1/2 bg-blue-600 hover:bg-blue-700 text-white px-8 py-2.5 rounded-xl transition-colors font-bold disabled:opacity-50 flex items-center gap-2 shadow-lg shadow-blue-600/20"
            >
              {loading ? <i className="fas fa-sync fa-spin"></i> : 'Buscar'}
            </button>
          </form>
          {view === ViewMode.SEARCH && results.length > 0 && (
            <div className="mt-4 flex flex-wrap gap-2">
               <button 
                onClick={() => setActiveFilter(null)}
                className={`px-4 py-1.5 rounded-full text-xs font-bold border transition-all ${!activeFilter ? 'bg-blue-600 text-white border-blue-600' : 'bg-white text-slate-600 border-slate-200 hover:border-blue-300'}`}
              >
                Todos
              </button>
              {sectors.map(s => (
                <button 
                  key={s}
                  onClick={() => setActiveFilter(s === activeFilter ? null : s)}
                  className={`px-4 py-1.5 rounded-full text-xs font-bold border transition-all ${activeFilter === s ? 'bg-blue-600 text-white border-blue-600' : 'bg-white text-slate-600 border-slate-200 hover:border-blue-300'}`}
                >
                  {s}
                </button>
              ))}
            </div>
          )}
        </header>

        {/* Dynamic Views */}
        <div className="max-w-6xl mx-auto">
          {view === ViewMode.SEARCH && (
            <>
              {loading ? (
                <div className="flex flex-col items-center justify-center py-24 text-slate-400">
                  <div className="relative mb-6">
                    <i className="fas fa-cog fa-spin text-5xl text-blue-600"></i>
                    <i className="fas fa-search absolute -right-2 -bottom-2 text-2xl text-slate-800"></i>
                  </div>
                  <p className="font-bold text-slate-600">Consultando Base de Dados TEC/NCM...</p>
                  <p className="text-sm mt-1 opacity-60">Utilizando Inteligência Artificial para classificação precisa.</p>
                </div>
              ) : results.length > 0 ? (
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 animate-in slide-in-from-bottom-4 duration-500">
                  {filteredResults.map(ncm => (
                    <NcmCard 
                      key={ncm.code} 
                      ncm={ncm} 
                      onSelect={handleSelectNcm}
                      isFavorite={favorites.some(f => f.code === ncm.code)}
                      onToggleFavorite={toggleFavorite}
                    />
                  ))}
                </div>
              ) : query && !loading ? (
                <div className="text-center py-20 text-slate-400 bg-white rounded-3xl border-2 border-dashed border-slate-200">
                  <i className="fas fa-triangle-exclamation text-amber-500 text-4xl mb-4"></i>
                  <p className="text-slate-700 font-bold text-lg">Produto não localizado</p>
                  <p className="text-sm">Tente termos mais genéricos ou o código numérico parcial.</p>
                </div>
              ) : (
                <div className="flex flex-col items-center justify-center py-16">
                   <div className="relative group mb-8">
                     <div className="absolute -inset-1 bg-gradient-to-r from-blue-600 to-slate-400 rounded-full blur opacity-25 group-hover:opacity-50 transition duration-1000"></div>
                     <img src="https://images.unsplash.com/photo-1581091226825-a6a2a5aee158?auto=format&fit=crop&q=80&w=400&h=300" className="relative w-72 h-48 object-cover rounded-3xl shadow-xl grayscale hover:grayscale-0 transition-all duration-500" alt="Industrial" />
                   </div>
                   <h2 className="text-xl font-black text-slate-800 mb-2">Consulta de Classificação Fiscal</h2>
                   <p className="text-slate-500 max-w-md text-center text-sm leading-relaxed">
                     Otimize sua logística e planejamento tributário com a ferramenta oficial da <span className="font-bold text-blue-600">Detecta Manutenção Industrial</span>.
                   </p>
                </div>
              )}
