                <button 
                  onClick={clearHistory}
                  className="text-red-500 hover:bg-red-50 px-4 py-2 rounded-xl text-sm font-bold transition-all"
                >
                  <i className="fas fa-trash-can mr-2"></i> Limpar
                </button>
              </div>
              {history.length > 0 ? (
                <div className="space-y-3">
                  {history.map((h, i) => (
                    <div 
                      key={i}
                      onClick={() => {
                        setQuery(h.query);
                        handleSearch();
                      }}
                      className="flex items-center justify-between p-5 bg-white border border-slate-200 rounded-2xl hover:border-blue-600 hover:shadow-lg cursor-pointer transition-all group shadow-sm"
                    >
                      <div className="flex items-center gap-4">
                        <div className="w-10 h-10 bg-slate-50 rounded-full flex items-center justify-center text-slate-400 group-hover:bg-blue-600 group-hover:text-white transition-all">
                          <i className="fas fa-search"></i>
                        </div>
                        <div>
                          <p className="font-bold text-slate-800 group-hover:text-blue-600">{h.query}</p>
                          <p className="text-[10px] text-slate-400 uppercase tracking-widest">Consulta realizada</p>
                        </div>
                      </div>
                      <span className="text-xs text-slate-400 font-medium">
                        {new Date(h.timestamp).toLocaleDateString('pt-BR')}
                      </span>
                    </div>
                  ))}
                </div>
              ) : (
                <p className="text-center text-slate-500 py-20 font-medium italic">Nenhuma busca recente registrada.</p>
              )}
            </div>
          )}

          {view === ViewMode.DETAILS && selectedNcm && (
            <div className="bg-white rounded-[2rem] shadow-2xl border border-slate-100 overflow-hidden max-w-4xl mx-auto animate-in zoom-in-95 duration-300">
              <div className="bg-slate-900 p-10 text-white relative">
                <button 
                  onClick={() => setView(ViewMode.SEARCH)}
                  className="absolute left-6 top-6 w-10 h-10 rounded-full bg-white/10 flex items-center justify-center hover:bg-white/20 transition-all border border-white/10"
