                  <i className="fas fa-arrow-left"></i>
                </button>
                <div className="text-center">
                  <div className="inline-flex items-center gap-2 px-4 py-1.5 bg-blue-600 rounded-full text-[10px] font-black uppercase tracking-[0.2em] mb-6 shadow-lg shadow-blue-600/40">
                    <i className="fas fa-check-circle"></i> Dados Oficiais Receita
                  </div>
                  <h2 className="text-5xl font-mono font-black mb-4 tracking-tighter text-blue-500">{selectedNcm.code}</h2>
                  <p className="text-slate-300 text-lg leading-relaxed max-w-2xl mx-auto font-medium">
                    {selectedNcm.description}
                  </p>
                </div>
              </div>

              <div className="p-10">
                <div className="grid grid-cols-2 md:grid-cols-5 gap-4 mb-12">
                  {[
                    { label: 'II', val: selectedNcm.taxes.ii, icon: 'fa-globe' },
                    { label: 'IPI', val: selectedNcm.taxes.ipi, icon: 'fa-industry' },
                    { label: 'PIS', val: selectedNcm.taxes.pis, icon: 'fa-receipt' },
                    { label: 'COFINS', val: selectedNcm.taxes.cofins, icon: 'fa-file-invoice' },
                    { label: 'ICMS (MÉD)', val: selectedNcm.taxes.icms_avg, icon: 'fa-truck' },
                  ].map((tax, idx) => (
                    <div key={idx} className="p-5 bg-slate-50 rounded-3xl text-center border border-slate-100 shadow-sm hover:border-blue-200 transition-all">
                      <i className={`fas ${tax.icon} text-slate-300 mb-2 text-xs`}></i>
                      <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest mb-1">{tax.label}</p>
                      <p className="text-2xl font-black text-slate-800">{tax.val}</p>
                    </div>
                  ))}
                </div>

                <div className="grid md:grid-cols-2 gap-8">
                  <div className="space-y-8">
                    <div>
                      <h3 className="text-sm font-black text-slate-800 mb-4 flex items-center gap-2 uppercase tracking-widest">
                        <i className="fas fa-triangle-exclamation text-amber-500"></i>
                        Restrições Aduaneiras
                      </h3>
                      <div className="bg-amber-50 border border-amber-100 rounded-2xl p-6">
                        {selectedNcm.restrictions && selectedNcm.restrictions.length > 0 ? (
                          <ul className="space-y-3">
                            {selectedNcm.restrictions.map((r, i) => (
                              <li key={i} className="flex gap-3 text-amber-900 text-xs font-medium leading-relaxed">
                                <span className="text-amber-400">•</span>
                                {r}
                              </li>
                            ))}
                          </ul>
                        ) : (
                          <p className="text-amber-800 text-xs italic">Não há restrições especiais ou licenças de importação automáticas para este código.</p>
                        )}
                      </div>
                    </div>
                  </div>

                  <div className="space-y-8">
                    <div>
                      <h3 className="text-sm font-black text-slate-800 mb-4 flex items-center gap-2 uppercase tracking-widest">
                        <i className="fas fa-briefcase text-blue-600"></i>
                        Recomendação de Uso
                      </h3>
                      <div className="bg-blue-50 border border-blue-100 rounded-2xl p-6 text-xs text-blue-900 leading-relaxed font-medium">
                        Este NCM é tipicamente vinculado ao setor <span className="text-blue-700 font-bold">{selectedNcm.sector || 'Técnico Geral'}</span>. 
                        A <span className="font-bold">Detecta</span> recomenda conferir se o produto requer tratamento administrativo especial antes da importação ou saída de fábrica.
                      </div>
                    </div>
                  </div>
                </div>

                <div className="mt-12 flex flex-col sm:flex-row gap-4">
                  <button 
                    onClick={(e) => toggleFavorite(e, selectedNcm)}
                    className={`flex-grow py-5 rounded-2xl font-black text-sm uppercase tracking-widest transition-all flex items-center justify-center gap-3 ${favorites.some(f => f.code === selectedNcm.code) ? 'bg-amber-100 text-amber-700 border border-amber-200' : 'bg-slate-100 text-slate-700 hover:bg-slate-200 border border-slate-200'}`}
                  >
                    <i className={favorites.some(f => f.code === selectedNcm.code) ? "fas fa-star" : "far fa-star"}></i>
                    {favorites.some(f => f.code === selectedNcm.code) ? 'Remover Favorito' : 'Adicionar aos Favoritos'}
                  </button>
                  <button 
                    onClick={() => window.print()}
                    className="bg-blue-600 text-white px-10 rounded-2xl font-black text-sm uppercase tracking-widest hover:bg-blue-700 transition-all flex items-center justify-center gap-3 shadow-xl shadow-blue-600/30"
                  >
                    <i className="fas fa-file-pdf"></i>
                    Exportar Laudo
                  </button>
                </div>
              </div>
            </div>
          )}
        </div>
      </main>
    </div>
  );
};

export default App;

