import { useState, useEffect } from 'react';
import { Ncm } from './types';
import NcmCard from './components/NcmCard';

export enum ViewMode {
  SEARCH = 'search',
  FAVORITES = 'favorites',
  HISTORY = 'history',
}

function App() {
  const [searchTerm, setSearchTerm] = useState<string>('');
  const [filteredResults, setFilteredResults] = useState<Ncm[]>([]);
  const [favorites, setFavorites] = useState<Ncm[]>(() => {
    const saved = localStorage.getItem('favorites');
    const initialValue = JSON.parse(saved || '[]');
    return initialValue;
  });
  const [history, setHistory] = useState<string[]> ( () => {
    const saved = localStorage.getItem('history');
    const initialValue = JSON.parse(saved || '[]');
    return initialValue;
  });
  const [selectedNcm, setSelectedNcm] = useState<Ncm | null>(null);
  const [view, setView] = useState<ViewMode>(ViewMode.SEARCH);
  const [loading, setLoading] = useState<boolean>(false);

  useEffect(() => {
    localStorage.setItem('favorites', JSON.stringify(favorites));
  }, [favorites]);

  useEffect(() => {
    localStorage.setItem('history', JSON.stringify(history));
  }, [history]);

  const handleSearch = async () => {
    setLoading(true);
    setFilteredResults([]);
    // Simulate API call with a delay
    setTimeout(() => {
        const results = [
          { code: '3808.99.10', description: 'Inseticidas', aladi: 'A004', ncm_completa: '3808.99.10' },
          { code: '8471.30.12', description: 'Computadores', aladi: 'A005', ncm_completa: '8471.30.12' },
          // ... more results
        ];
        const normalizedSearchTerm = searchTerm.toLowerCase();
        const filtered = results.filter(ncm =>
            ncm.code.toLowerCase().includes(normalizedSearchTerm) ||
            ncm.description.toLowerCase().includes(normalizedSearchTerm)
        );
        setFilteredResults(filtered);
        setHistory(prevHistory => {
            const newHistory = [searchTerm, ...prevHistory.filter(term => term !== searchTerm)].slice(0, 5);
            return newHistory;
        });
        setLoading(false);
    }, 500);
  };

  const handleSelectNcm = (ncm: Ncm) => {
    setSelectedNcm(ncm);
    setView(ViewMode.SEARCH); // Optionally, reset to SEARCH view
