import { GoogleGenAI, Type } from "@google/genai";
import { NcmData } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const NCM_SCHEMA = {
  type: Type.ARRAY,
  items: {
    type: Type.OBJECT,
    properties: {
      code: { type: Type.STRING, description: "Código NCM formatado (ex: 8517.12.00)" },
      description: { type: Type.STRING, description: "Descrição oficial da Nomenclatura" },
      sector: { type: Type.STRING, description: "Setor comercial/industrial geral" },
      taxes: {
        type: Type.OBJECT,
        properties: {
          ii: { type: Type.STRING, description: "Alíquota Imposto de Importação (%)" },
          ipi: { type: Type.STRING, description: "Alíquota IPI (%)" },
          pis: { type: Type.STRING, description: "Alíquota PIS (%)" },
          cofins: { type: Type.STRING, description: "Alíquota COFINS (%)" },
          icms_avg: { type: Type.STRING, description: "Média estimada ICMS (%)" }
        },
        required: ["ii", "ipi", "pis", "cofins", "icms_avg"]
      },
      restrictions: {
        type: Type.ARRAY,
        items: { type: Type.STRING },
        description: "Eventuais restrições ou licenças de importação"
      },
      isObsolete: { type: Type.BOOLEAN, description: "Define se o NCM foi descontinuado ou substituído" },
      replacementCode: { type: Type.STRING, description: "Se isObsolete for true, indique o código que o substituiu" },
      statusNote: { type: Type.STRING, description: "Explicação sobre a mudança de status (ex: Descontinuado na Resolução GECEX 272/2021)" },
      relevance: { type: Type.NUMBER, description: "Score de relevância de 0 a 1" }
    },
    required: ["code", "description", "taxes"]
  }
};

export const searchNcm = async (query: string): Promise<NcmData[]> => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Atue como um especialista fiscal brasileiro. Busque o código NCM para: "${query}". 
      REGRA CRÍTICA: Sempre verifique se o NCM é vigente. Se o código informado for antigo (ex: 7306.30.00), você DEVE marcar 'isObsolete' como true, informar o 'replacementCode' (ex: 7306.30.90) e explicar no 'statusNote'.
      Retorne os dados formatados de acordo com a TIPI e TEC vigentes em 2024/2025.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: NCM_SCHEMA as any,
      },
    });

    const results = JSON.parse(response.text || "[]");
    return results;
  } catch (error) {
    console.error("Erro ao buscar NCM:", error);
    return [];
  }
};

export const getNcmByCode = async (code: string): Promise<NcmData | null> => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Forneça detalhes do NCM "${code}". Verifique especificamente se ele foi substituído recentemente. Se sim, informe o substituto.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: (NCM_SCHEMA as any).items
        } as any,
      },
    });

    const results = JSON.parse(response.text || "[]");
    return results.length > 0 ? results[0] : null;
  } catch (error) {
    console.error("Erro ao obter detalhes do NCM:", error);
    return null;
  }
};

