          </div>
          <div className="mt-3 flex items-center justify-between px-1">
            <span className="text-[10px] font-black text-slate-500 tracking-widest uppercase">Portal NCM</span>
          </div>
        </div>

        <ul className="space-y-2 flex-grow">
          <li>
            <button onClick={() => setView(ViewMode.SEARCH)} className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition-colors ${view === ViewMode.SEARCH ? 'bg-blue-600 text-white shadow-lg' : 'hover:bg-slate-800'}`}>
              <i className="fas fa-search"></i> Consulta
            </button>
          </li>
          <li>
            <button onClick={() => setView(ViewMode.FAVORITES)} className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition-colors ${view === ViewMode.FAVORITES ? 'bg-slate-800 text-white' : 'hover:bg-slate-800'}`}>
              <i className="fas fa-star"></i> Favoritos
            </button>
          </li>
          <li>
            <button onClick={() => setView(ViewMode.HISTORY)} className={`w-full flex items-center gap-3 px-4 py-3 rounded-lg transition-colors ${view === ViewMode.HISTORY ? 'bg-slate-800 text-white' : 'hover:bg-slate-800'}`}>
