import { GoogleGenAI, Type } from "@google/genai";
import { NcmData } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const NCM_SCHEMA = {
  type: Type.ARRAY,
  items: {
    type: Type.OBJECT,
    properties: {
      code: { type: Type.STRING, description: "Código NCM formatado (ex: 8517.12.00)" },
      description: { type: Type.STRING, description: "Descrição oficial da Nomenclatura" },
      sector: { type: Type.STRING, description: "Setor comercial/industrial geral" },
      taxes: {
        type: Type.OBJECT,
        properties: {
          ii: { type: Type.STRING, description: "Alíquota Imposto de Importação (%)" },
          ipi: { type: Type.STRING, description: "Alíquota IPI (%)" },
          pis: { type: Type.STRING, description: "Alíquota PIS (%)" },
          cofins: { type: Type.STRING, description: "Alíquota COFINS (%)" },
          icms_avg: { type: Type.STRING, description: "Média estimada ICMS (%)" }
        },
        required: ["ii", "ipi", "pis", "cofins", "icms_avg"]
      },
      restrictions: {
        type: Type.ARRAY,
        items: { type: Type.STRING },
        description: "Eventuais restrições ou licenças de importação"
      },
      isObsolete: { type: Type.BOOLEAN, description: "Define se o NCM foi descontinuado ou substituído" },
      replacementCode: { type: Type.STRING, description: "Se isObsolete, indique o(s) código(s) novo(s). Se houver vários, cite os principais." },
      statusNote: { type: Type.STRING, description: "Explicação técnica: Por que mudou? Se foi desdobrado, qual a diferença técnica entre as novas opções?" },
      relevance: { type: Type.NUMBER, description: "Score de relevância de 0 a 1" }
    },
    required: ["code", "description", "taxes"]
  }
};

export const searchNcm = async (query: string): Promise<NcmData[]> => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Atue como um Consultor Fiscal Sênior especializado em Comércio Exterior e TIPI. 
      Analise o termo ou código: "${query}". 

      REGRAS CRÍTICAS DE SEGURANÇA:
      1. Se o código (ex: 7306.30.00) foi EXTINTO e DESDOBRADO em vários (ex: 7306.30.10 e 7306.30.90), você DEVE retornar as novas opções como resultados individuais válidos e marcar o antigo como obsoleto.
      2. No 'statusNote', explique EXATAMENTE a diferença técnica (ex: '7306.30.10 é para galvanizados, enquanto 7306.30.90 abrange os demais').
      3. Use como base a última atualização da TIPI (Tabela de IPI) e TEC (Tarifa Externa Comum) de 2024/2025.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: NCM_SCHEMA as any,
      },
    });

    const results = JSON.parse(response.text || "[]");
    return results;
  } catch (error) {
    console.error("Erro ao buscar NCM:", error);
    return [];
  }
};

export const getNcmByCode = async (code: string): Promise<NcmData | null> => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Forneça detalhes técnicos profundos do NCM "${code}". Verifique histórico de alterações nos últimos 3 anos.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: (NCM_SCHEMA as any).items
        } as any,
      },
    });

    const results = JSON.parse(response.text || "[]");
    return results.length > 0 ? results[0] : null;
  } catch (error) {
    console.error("Erro ao obter detalhes do NCM:", error);
    return null;
  }
};

