    if (e) e.preventDefault();
    const searchTerm = customQuery || query;
    if (!searchTerm.trim()) return;

    setLoading(true);
    setView(ViewMode.SEARCH);

    const newHistory = [
      { query: searchTerm, timestamp: Date.now() },
      ...history.filter(h => h.query !== searchTerm)
    ].slice(0, 10);
