                          <span className="font-bold text-slate-700">{h.query}</span>
                        </div>
                        <span className="text-[10px] font-bold text-slate-300">{new Date(h.timestamp).toLocaleDateString()}</span>
                      </div>
                    ))}
                  </div>
                )}
              </div>
            </div>
          )}
        </div>
      </main>
    </div>
  );
};

