                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
                  {favorites.map(ncm => (
                    <NcmCard 
                      key={ncm.code} 
                      ncm={ncm} 
                      onSelect={handleSelectNcm} 
                      isFavorite={true} 
                      onToggleFavorite={toggleFavorite}
                      updateNote={updates[ncm.code] || undefined}
                    />
                  ))}
                </div>
              )}
            </div>
          )}

          {view === ViewMode.HISTORY && (
            <div className="max-w-2xl mx-auto">
              <div className="flex justify-between items-center mb-6">
                <h2 className="text-2xl font-black text-slate-800">Recentes</h2>
                <button onClick={clearHistory} className="text-xs font-bold text-red-500 uppercase tracking-widest">Limpar</button>
              </div>
              <div className="bg-white rounded-3xl border border-slate-200 shadow-sm overflow-hidden divide-y divide-slate-100">
                {history.map((h, i) => (
                  <div key={i} className="p-5 flex items-center justify-between hover:bg-slate-50 cursor-pointer" onClick={() => { setQuery(h.query); handleSearch(undefined, h.query); }}>
                    <div className="flex items-center gap-4">
                      <div className="w-10 h-10 rounded-xl bg-slate-100 flex items-center justify-center text-slate-400">
                        <i className="fas fa-search text-xs"></i>
                      </div>
                      <span className="font-bold text-slate-700">{h.query}</span>
                    </div>
                    <span className="text-[10px] font-bold text-slate-300">{new Date(h.timestamp).toLocaleDateString()}</span>
                  </div>
                ))}
              </div>
            </div>
          )}
        </div>
      </main>
    </div>
  );
};

export default App;

