        </button>
        <button 
          onClick={() => setActiveTab('xml')}
          className={`flex-1 py-3 rounded-xl font-bold text-sm transition-all ${activeTab === 'xml' ? 'bg-white text-emerald-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
        >
          <i className="fas fa-code mr-2"></i> Conteúdo XML (Nota Real)
        </button>
      </div>

      <div className="bg-white p-8 rounded-3xl border border-slate-200 shadow-xl space-y-6">
        {activeTab === 'key' ? (
          <div className="space-y-4">
            <div className="space-y-2">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Chave de Acesso (44 dígitos)</label>
              <input 
                type="text" 
                maxLength={44}
                value={nfKey}
                onChange={(e) => setNfKey(e.target.value.replace(/\D/g, ''))}
                placeholder="Insira a chave da NF-e..."
                className="w-full p-5 bg-slate-50 border border-slate-200 rounded-2xl font-mono text-xl text-center tracking-[0.1em] outline-none focus:ring-4 focus:ring-blue-500/10 focus:border-blue-500 transition-all"
              />
              <div className="flex justify-between px-1">
                <span className="text-[10px] text-slate-400 font-bold">{nfKey.length} / 44 dígitos</span>
              </div>
            </div>
            <div className="p-4 bg-amber-50 rounded-xl border border-amber-100 flex gap-3">
              <i className="fas fa-triangle-exclamation text-amber-500 mt-1"></i>
              <p className="text-[11px] text-amber-800 leading-relaxed">
                <strong>Nota:</strong> A consulta por chave sem certificado digital pode ser imprecisa para itens específicos de notas privadas. Para precisão total, utilize a aba <strong>Conteúdo XML</strong>.
              </p>
            </div>
          </div>
        ) : (
          <div className="space-y-4">
            <div className="space-y-2">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Cole o Conteúdo do XML da Nota</label>
              <textarea 
                value={xmlContent}
                onChange={(e) => setXmlContent(e.target.value)}
                rows={8}
                placeholder="Cole aqui o conteúdo do arquivo .xml da nota fiscal..."
                className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl font-mono text-xs outline-none focus:ring-4 focus:ring-emerald-500/10 focus:border-emerald-500 transition-all resize-none"
              />
            </div>
            <p className="text-[11px] text-slate-400 italic text-center">
              Ao colar o XML, a IA lerá as tags reais de cada produto (<span className="font-mono">&lt;xProd&gt;</span> e <span className="font-mono">&lt;NCM&gt;</span>).
            </p>
          </div>
        )}

        <button 
          onClick={handleProcess}
          disabled={loading || (activeTab === 'key' && nfKey.length < 44) || (activeTab === 'xml' && !xmlContent)}
          className={`w-full py-5 rounded-2xl font-black text-lg shadow-2xl transition-all flex items-center justify-center gap-3 disabled:opacity-50 ${activeTab === 'key' ? 'bg-slate-900 shadow-slate-900/20' : 'bg-emerald-600 shadow-emerald-600/20'} text-white`}
        >
          {loading ? (
            <>
              <i className="fas fa-sync fa-spin"></i>
              Processando Documento...
            </>
          ) : (
            <>
              <i className={activeTab === 'key' ? "fas fa-magnifying-glass-chart" : "fas fa-file-import"}></i>
              {activeTab === 'key' ? 'Analisar pela Chave' : 'Importar Dados do XML'}
            </>
          )}
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        <div className="p-4 bg-white/50 rounded-2xl border border-slate-200/50 flex items-center gap-3">
          <i className="fas fa-shield-check text-emerald-500"></i>
          <div>
            <p className="text-[10px] font-black text-slate-600 uppercase tracking-tighter">Precisão Máxima</p>
            <p className="text-[9px] text-slate-400">Extração direta das tags oficiais do XML.</p>
          </div>
        </div>
        <div className="p-4 bg-white/50 rounded-2xl border border-slate-200/50 flex items-center gap-3">
          <i className="fas fa-calculator text-blue-500"></i>
          <div>
            <p className="text-[10px] font-black text-slate-600 uppercase tracking-tighter">Cálculo Automático</p>
            <p className="text-[9px] text-slate-400">Verificação instantânea de alíquotas por item.</p>
          </div>
        </div>
      </div>
    </div>
  );
};

